diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 706cb828acc6..3e8933e0ae09 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -4149,6 +4149,53 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
       return BinaryOperator::CreateOr(Ov, NewCmp);
     }
   }
+  // Similar to above, but for multiplication: Overflow | icmp pred Res, C2
+  // where Res, Overflow = mul.with.overflow X, C1.
+  // The condition Overflow | (Res pred C2) can be transformed to X pred' NewC,
+  // where NewC is derived from C2 and C1 based on predicate and signedness.
+  if (match(&I, m_c_Or(m_CombineAnd(m_ExtractValue<1>(m_CombineAnd(
+                                        m_WithOverflowInst(WO), m_Value(WOV))),
+                                    m_Value(Ov)),
+                       m_OneUse(m_ICmp(Pred, m_ExtractValue<0>(m_Deferred(WOV)),
+                                       m_APInt(C2))))) &&
+      WO->getBinaryOp() == Instruction::Mul &&
+      (ICmpInst::isEquality(Pred) ||
+       WO->isSigned() == ICmpInst::isSigned(Pred)) &&
+      match(WO->getRHS(), m_APInt(C1))) {
+    // Avoid division by zero.
+    if (C1->isZero())
+      return nullptr;
+    // For now, only handle unsigned multiplication and unsigned comparisons.
+    if (!WO->isSigned() && ICmpInst::isUnsigned(Pred)) {
+      const APInt &D = *C1;
+      const APInt &N = *C2;
+      APInt NewC;
+      switch (Pred) {
+      case ICmpInst::ICMP_UGT:
+        // X * D > N  <=> X > N.udiv(D)
+        NewC = N.udiv(D);
+        break;
+      default:
+        return nullptr;
+      }
+      // Now we have NewC such that X Pred NewC is equivalent to original OR,
+      // where Pred is same as original for UGT.
+      // However, we must also consider overflow flag: for X > bound, overflow flag is automatically true.
+      // Therefore we can replace the whole OR with X Pred NewC.
+      // But we must ensure that overflow flag is not used elsewhere.
+      // If Ov has one use (the OR), we can replace OR entirely.
+      if (Ov->hasOneUse()) {
+        Value *NewCmp = Builder.CreateICmp(Pred, WO->getLHS(),
+                                           ConstantInt::get(WO->getLHS()->getType(), NewC));
+        return replaceInstUsesWith(I, NewCmp);
+      } else {
+        // Keep overflow flag.
+        Value *NewCmp = Builder.CreateICmp(Pred, WO->getLHS(),
+                                           ConstantInt::get(WO->getLHS()->getType(), NewC));
+        return BinaryOperator::CreateOr(Ov, NewCmp);
+      }
+    }
+  }

   // (~x) | y  -->  ~(x & (~y))  iff that gets rid of inversions
   if (sinkNotIntoOtherHandOfLogicalOp(I))

